type Mutation {
  createOrder(input: CreateOrderInput!): OrderPayload!
}

input CreateOrderInput {
  idempotencyKey: ID!
  items: [OrderItemInput!]!
}

// Resolver (Apollo Server)
async createOrder(_: unknown, { input }: Args, { redis }: Context) {
  const cached = await redis.get(`idem:${input.idempotencyKey}`);
  if (cached) return JSON.parse(cached);

  const order = await db.orders.create(input);
  await redis.setex(`idem:${input.idempotencyKey}`, 86400, JSON.stringify(order));
  return order;
}

